<?php $url = "https://billing.leopharma.tech/API/announcements/bill_master.php"; $cucodes = ["050001", "050014", "050034", "050042", "050043", "050046", "050048"]; foreach($cucodes as $c) { $ch = curl_init($url); curl_setopt($ch, CURLOPT_POST, 1); curl_setopt($ch, CURLOPT_POSTFIELDS, ["cucode" => $c, "from_date" => "2026-06-01", "to_date" => "2026-06-02"]); curl_setopt($ch, CURLOPT_HTTPHEADER, ["ngrok-skip-browser-warning: true"]); curl_setopt($ch, CURLOPT_RETURNTRANSFER, true); $res = curl_exec($ch); echo "$c: $res\n"; }
